/**
 * BUILD METADATA — CANONICAL SHAPE
 * This node defines the contract for the rest of the workflow
 */

// Prefer Drive-reported size, fall back to binary metadata if needed
const fileSize =
  Number($json.size) ||
  Number($binary?.data?.fileSize) ||
  null;

console.log('=== BUILD METADATA ===' );
console.log('File ID:', $json.id);
console.log('File Name:', $json.name);
console.log('File Size:', fileSize);

return {
  json: {
    // Canonical fields used everywhere downstream
    file_id: $json.id,
    document_name: $json.name,
    mime_type: $json.mimeType,
    file_size_bytes: fileSize,
    drive_modified_time: $json.modifiedTime || null,
    drive_created_time: $json.createdTime || null
  },
  binary: $binary
};

const metadata = $items('Build Metadata')[0].json;
const fileId = metadata.file_id;

console.log('=== CHECKING CACHE ===');
console.log('File ID to check:', fileId);

// Get the Supabase result from the previous node
const supabaseResults = $items('Check Cache');

console.log('Supabase node returned:', supabaseResults.length, 'items');
console.log('Full Supabase response:', JSON.stringify(supabaseResults, null, 2));

let cacheHit = false;
let cacheRecord = null;

if (supabaseResults && supabaseResults.length > 0) {
  const result = supabaseResults[0].json;
  console.log('First result:', JSON.stringify(result, null, 2));

  // Check if this is a real record with data
  if (result && typeof result === 'object') {
    const keys = Object.keys(result);
    console.log('Keys in result:', keys);

    if (keys.length > 0 && result.file_id) {
      cacheHit = true;
      cacheRecord = result;
      console.log('✅ CACHE HIT - Found record with file_id:', result.file_id);
    } else if (keys.length === 0) {
      console.log('❌ CACHE MISS - Empty object returned');
    } else {
      console.log('❌ CACHE MISS - No file_id in result');
    }
  }
} else {
  console.log('❌ CACHE MISS - No results from Supabase');
}

console.log('Final cache_hit decision:', cacheHit);

return {
  json: {
    ...metadata,
    cache_hit: cacheHit,
    cache_record: cacheRecord,
    debug_supabase_length: supabaseResults.length,
    debug_raw_response: supabaseResults.length > 0 ? supabaseResults[0].json : null
  },
  binary: $items('Build Metadata')[0].binary
};

console.log('✅ WORKFLOW STOPPED - File already in cache');
console.log('File:', $json.document_name);
console.log('File ID:', $json.file_id);

return $input.all();

/**
 * COMBINE METADATA + JOB ID
 * Merge file metadata with the Landing.ai job_id
 */

const metadata = $items('Debug Cache Results')[0].json;
const jobResponse = $items('Submit to Landing.ai')[0].json;

console.log('=== MERGING DATA ===');
console.log('Metadata:', metadata);
console.log('Job Response:', jobResponse);

return {
  json: {
    // File metadata
    file_id: metadata.file_id,
    document_name: metadata.document_name,
    mime_type: metadata.mime_type,
    file_size_bytes: metadata.file_size_bytes,

    // Job info
    job_id: jobResponse.job_id,

    // Loop control
    max_retries: 20,
    poll_interval_sec: 10,
    loop_start_time: Date.now(),
    max_loop_duration_sec: 3600
  }
};

console.log('✅ WORKFLOW COMPLETE - Parse successful');
console.log('File:', $json.document_name);
console.log('Pages:', $json.page_count);
console.log('Job ID:', $json.job_id);

return $input.all();

console.log('❌ WORKFLOW FAILED - Parse timeout');
console.log('File:', $json.document_name);
console.log('Retries:', $json.retry_count);
console.log('Elapsed:', $json.elapsed_seconds + 's');

return $input.all();
